# @cctt_verify {"v":2,"sym":"sympy.core.cache.lazy_function","kind":"function","src_hash":"b612116137e06775","in":{"base":"str"},"out":{"base":"Callable"},"spec":{"lhs":"lazy_function(mod)","rhs":"create a lazy proxy for a function in a module","over":{"base":"str"},"name":"lazy_function_correct"},"guarantee":"create a lazy proxy for a function in a module","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.cache.lazy_function_correct","statement":"Path(lazy_function(x), create a lazy proxy for a function in a module)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"628768098902d346"}
def lazy_function(module : str, name : str) -> Callable:
    """Create a lazy proxy for a function in a module.

    The module containing the function is not imported until the function is used.

    """
    func = None

    def _get_function():
        nonlocal func
        if func is None:
            func = getattr(import_module(module), name)
        return func

    # The metaclass is needed so that help() shows the docstring
    class LazyFunctionMeta(type):
        @property
        def __doc__(self):
            docstring = _get_function().__doc__
            docstring += f"\n\nNote: this is a {self.__class__.__name__} wrapper of '{module}.{name}'"
            return docstring

    class LazyFunction(metaclass=LazyFunctionMeta):
        def __call__(self, *args, **kwargs):
            # inline get of function for performance gh-23832
            nonlocal func
            if func is None:
                func = getattr(import_module(module), name)
            return func(*args, **kwargs)

        @property
        def __doc__(self):
            docstring = _get_function().__doc__
            docstring += f"\n\nNote: this is a {self.__class__.__name__} wrapper of '{module}.{name}'"
            return docstring

        def __str__(self):
            return _get_function().__str__()

        def __repr__(self):
            return f"<{__class__.__name__} object at 0x{id(self):x}>: wrapping '{module}.{name}'"

    return LazyFunction()
